<template>
    <v-card light>
        <v-card-title class="headline primary" style="color:white;" primary-title dark>走行ログの保存</v-card-title>
        <v-form v-model="isFormValid" ref="cycle_log_save_form">
            <v-container>
                <v-row>
                    <v-col cols="12">
                        <v-text-field dense outlined label="走行ログ名" color="primary" v-model="modelTitle" v-bind:rules="[required]"></v-text-field>
                    </v-col>
                </v-row>
            </v-container>
        </v-form>
        <v-card-actions>
            <v-spacer></v-spacer>
            <v-btn v-on:click="sendResult(1)" color="primary" dark>保存する</v-btn>
            <v-btn v-on:click="sendResult(2)" color="primary" dark>保存しない</v-btn>
            <v-btn v-on:click="sendResult(0)">キャンセル</v-btn>
        </v-card-actions>
    </v-card>
</template>

<script>
export default {
    props: ["location"],
    data() {
        return {
            endDate: null,
            isFormValid: false,
            modelTitle: "",
            required: value => !!value || "必須入力"
        };
    },
    mounted() {
        this.endDate = new Date();
    },
    methods: {
        sendResult(flg) {
            if (flg == 1) {
                this.isFormValid = this.$refs.cycle_log_save_form.validate();
                if (!this.isFormValid) {
                    return;
                }
            }

            if (flg == 1) {
                this.addCycleLog({
                    id: this.location.id,
                    startDate: this.location.startDate,
                    endDate: this.endDate,
                    title: this.modelTitle,
                    distance: this.location.distance
                });
            }

            this.$emit("save-result", flg);
        }
    }
};
</script>
