<script>
export default {
    install(Vue, options) {
        Vue.mixin({
            methods: {
                getCycleLog() {
                    return this.getData("cycle_log");
                },
                getData(key) {
                    var data = JSON.parse(localStorage.getItem(key));
                    if (data == null) {
                        return [];
                    }
                    return data;
                },
                addCycleLog(data) {
                    var log = this.getCycleLog();
                    log.push(data);
                    this.setCycleLog(log);
                },
                deleteCycleLog(id) {
                    var cycleLog = this.getCycleLog();
                    var filterData = cycleLog.filter(function(data, index) {
                        if (data.id != id) return true;
                    });
                    this.setCycleLog(filterData);
                },
                setCycleLog(data) {
                    this.setData("cycle_log", data);
                },
                setData(key, data) {
                    localStorage.setItem(key, JSON.stringify(data));
                }
            }
        });
    }
};
</script>
