<template>
    <v-container>
        <v-row>
            <v-col cols="auto">
                経過時間
            </v-col>
            <v-spacer></v-spacer>
            <v-col cols="auto">
                {{ locationProp.elapsedTime | filterElapsed }}
            </v-col>
        </v-row>
        <v-row>
            <v-col cols="auto">
                距離
            </v-col>
            <v-spacer></v-spacer>
            <v-col cols="auto">
                {{ locationProp.distance | filterDistance }}
            </v-col>
        </v-row>
        <v-row>
            <v-col cols="auto">
                速度
            </v-col>
            <v-spacer></v-spacer>
            <v-col cols="auto">
                {{ locationProp.speed | filterSpeed }}
            </v-col>
        </v-row>
    </v-container>
</template>

<script>
export default {
    data() {
        return {};
    },
    filters: {
        filterElapsed: function(n) {
            var hour = (n / (60 * 60)).toFixed(0);
            var min = ((n / 60) % 60).toFixed(0);
            var sec = (n % 60).toFixed(0);
            return hour + ":" + ("0" + min).slice(-2) + ":" + ("0" + sec).slice(-2);
        },
        filterSpeed: function(n) {
            return (n / 1000).toFixed(1) + " km/h";
        },
        filterDistance: function(n) {
            return n.toFixed(1) + " km";
        }
    },
    inject: ["locationProp"],
    mounted() {},
    methods: {}
};
</script>
