<template>
    <v-app>
        <v-app-bar app color="primary" dark>
            <!-- <v-btn v-on:click="onClickSettings" icon> <v-icon>fas fa-bars</v-icon></v-btn> -->
            <v-toolbar-title>CycleMagic</v-toolbar-title>
            <v-spacer></v-spacer>
            <!-- <v-btn v-on:click="test" style="margin-left:8px;" text>
                位置情報変更
            </v-btn>
            <v-btn v-on:click="getLocation" style="margin-left:8px;" text>
                位置情報取得
            </v-btn> -->
            <!-- <v-btn v-on:click="onClickStartRecording" style="margin-left:8px;" text>
                位置情報監視
            </v-btn> -->
            <!-- <v-btn v-on:click="onClickSettings" style="margin-left:8px;" icon> <v-icon>fas fa-search</v-icon></v-btn> -->
            <v-btn v-if="!showSettingsOverlay" v-on:click="onClickSettings" style="margin-left:8px;" icon> <v-icon>fas fa-cog</v-icon></v-btn>
            <v-btn v-if="showSettingsOverlay" v-on:click="onClickSettings" style="margin-left:8px;" icon> <v-icon>fas fa-times</v-icon></v-btn>
            <!-- <v-btn v-on:click="onClickSettings" style="margin-left:8px;" text>
                <font-awesome-icon icon="['fa', 'cog']" style="margin-right:5px;" />設定
            </v-btn> -->
        </v-app-bar>

        <v-content>
            <!-- <router-view> </router-view> -->
            <mapview ref="mapview"></mapview>
            <v-fab-transition>
                <v-btn v-show="!isRecording" v-on:click="onClickRecord" color="primary" fab large dark fixed bottom right class="record-icon">
                    <v-icon>fas fa-bicycle</v-icon>
                </v-btn>
            </v-fab-transition>
            <v-fab-transition>
                <v-btn v-show="isRecording" v-on:click="onClickRecord" color="error" fab large dark fixed bottom right class="record-icon">
                    <v-icon>fas fa-stop-circle</v-icon>
                </v-btn>
            </v-fab-transition>
            <v-overlay absolute :opacity="0.75" :value="showSettingsOverlay">
                <settings ref="settings" style="width:100%;height:100%;"></settings>
            </v-overlay>
            <v-overlay absolute :opacity="0.75" :value="showSaveOverlay">
                <saveCycleLog v-bind:location="location" v-on:save-result="saveResult"></saveCycleLog>
            </v-overlay>
        </v-content>
    </v-app>
</template>

<script>
import mapview from "./components/MapView.vue";
import settings from "./components/Settings.vue";
import saveCycleLog from "./components/SaveCycleLog.vue";
import getlocationCommon from "./js/GeolocationCommon";

export default {
    name: "App",
    provide: function() {
        return {
            locationProp: this.location
        };
    },
    components: {
        mapview,
        settings,
        saveCycleLog
    },
    mounted() {
        // this.$router.replace({ path: "/cyclemagic/MapView" });
    },
    data: () => ({
        id: 0,
        isRecording: false,
        options: {
            enableHighAccuracy: false,
            timeout: 5000,
            maximumAge: 0
        },
        // currentLocation: {
        //     position: { lat: 35.71, lng: 139.72 },
        //     title: "現在地"
        // },
        // locationLat: 0,
        // locationLng: 0,
        // mapViewProp: {
        //     moveToLocation: null
        // }
        location: {
            id: "",
            position: { lat: 35.71, lng: 139.72 },
            speed: 0,
            distance: 0,
            startDate: null,
            elapsedTime: 0,
            isEnableGps: false
        },
        isFirst: false,
        flg: false,
        showStartButton: true,
        showSettingsOverlay: false,
        showSaveOverlay: false
    }),
    methods: {
        onClickRecord() {
            if (this.isRecording) {
                this.endRecording();
            } else {
                // this.startRecording();
                this.createDigest(this.digestCallback);
            }
            // this.isRecording = !this.isRecording;
        },
        // onClickStartRecording() {
        //     if (this.isRecording) {
        //         this.endRecording();
        //     } else {
        //         this.startRecording();
        //     }
        //     this.isRecording = !this.isRecording;
        // },
        // startRecording() {
        //     this.createDigest(this.digestCallback);
        // },

        digestCallback(hex) {
            this.location.id = hex;
            this.startRecording();
            // this.$router.replace({ path: "/scoreapp/scoreinput" });
        },
        createDigest(callback) {
            if (!crypto || !crypto.subtle) {
                throw Error("crypto.subtle is not supported."); // ブラウザ未対応
            }
            var d = new Date();
            console.log(d.toLocaleString());
            var str = d.toLocaleString();

            crypto.subtle.digest("SHA-256", new TextEncoder().encode(str)).then(x => {
                const hex = this.hexString(x); // convert to hex string.
                callback(hex);
            });
        },
        hexString(buffer) {
            const byteArray = new Uint8Array(buffer);
            const hexCodes = [...byteArray].map(value => {
                const hexCode = value.toString(16);
                const paddedHexCode = hexCode.padStart(2, "0");
                return paddedHexCode;
            });
            return hexCodes.join("");
        },
        startRecording() {
            console.log("start Recording");
            this.id = navigator.geolocation.watchPosition(this.updateLocation, this.failed, this.options);
            this.location.speed = 0;
            this.location.distance = 0;
            this.location.startDate = new Date();
            this.isRecording = true;
            this.isFirst = true;
        },
        endRecording() {
            console.log("end Recording");
            // this.location.isEnableGps = false;
            this.showSaveOverlay = true;
        },
        saveResult(flg) {
            this.showSaveOverlay = false;
            if (flg != 0) {
                navigator.geolocation.clearWatch(this.id);
                this.isRecording = false;
            }
        },
        updateLocation(pos) {
            console.log("update location");
            this.location.isEnableGps = true;
            // var lat = pos.coords.latitude;
            // var lng = pos.coords.longitude;
            this.setLocation(pos.coords);
            // this.moveToLocation(lat, lng);
        },
        failed(err) {
            // this.location.isEnableGps = false;
            console.warn("ERROR(" + err.code + "): " + err.message);
        },
        getLocation() {
            if (navigator.geolocation) {
                var func = this.setLocation;

                navigator.geolocation.getCurrentPosition(function(pos) {
                    func(pos.coords.latitude, pos.coords.longitude);
                });
            } else {
                console.log("error geolocation!!");
            }
        },
        setLocation(coords) {
            console.log("setCurrentLocation");
            if (this.isFirst) {
                this.isFirst = !this.isFirst;
            } else {
                this.location.distance += getlocationCommon.getDistance(
                    this.location.position.lat,
                    this.location.position.lng,
                    coords.latitude,
                    coords.longitude
                );
            }
            this.location.position.lat = coords.latitude;
            this.location.position.lng = coords.longitude;
            this.location.speed = coords.speed;
            this.location.elapsedTime = (new Date().getTime() - this.location.startDate.getTime()) / 1000;

            this.$refs.mapview.updateLocation();
        },
        onClickSettings() {
            this.showSettingsOverlay = !this.showSettingsOverlay;
        }
    }
};
</script>

