export default {
    getDistance(lat1, lng1, lat2, lng2) {
        function radians(deg) {
            return (deg * Math.PI) / 180;
        }

        return (
            6378.14 *
            Math.acos(
                Math.cos(radians(lat1)) * Math.cos(radians(lat2)) * Math.cos(radians(lng2) - radians(lng1)) +
                    Math.sin(radians(lat1)) * Math.sin(radians(lat2))
            )
        );
    }
};
