<template>
    <v-list two-line light>
        <!-- <v-list-item-group v-model="selected" multiple active-class="pink--text"> -->
        <template v-for="(item, index) in cycleLog">
            <v-list-item :key="item.title">
                <!-- <template v-slot:default="{ active, toggle }"> -->
                <v-list-item-content>
                    <v-list-item-title>{{ item.title | filterTitle }}</v-list-item-title>
                    <v-list-item-subtitle class="text--primary">{{
                        new Date(item.startDate).toLocaleDateString() | filterCycleDate
                    }}</v-list-item-subtitle>
                    <!-- <v-list-item-subtitle class="text--primary">{{ item.startDate | filterStartDate }}</v-list-item-subtitle>
                    <v-list-item-subtitle class="text--primary">{{ item.endDate | filterEndDate }}</v-list-item-subtitle> -->
                    <v-list-item-subtitle class="text--primary">{{
                        (new Date(item.endDate).getTime() - new Date(item.startDate).getTime()) | filterElapsedTime
                    }}</v-list-item-subtitle>
                    <v-list-item-subtitle class="text--primary">{{ item.distance | filterDistance }}</v-list-item-subtitle>
                </v-list-item-content>

                <v-list-item-action>
                    <!-- <v-list-item-action-text v-text="item.title"></v-list-item-action-text> -->
                    <v-btn v-on:click="onClickTrash(item)" icon>
                        <v-icon color="primary">
                            fas fa-trash
                        </v-icon>
                    </v-btn>
                </v-list-item-action>
                <!-- </template> -->
            </v-list-item>

            <v-divider v-if="index + 1 < cycleLog.length" :key="index"></v-divider>
        </template>
        <!-- </v-list-item-group> -->
        <div v-if="cycleLog.length < 1" style="margin:10px;">走行データがありません</div>
    </v-list>
</template>

<script>
export default {
    data() {
        return {
            cycleLog: []
        };
    },
    filters: {
        // filterStartDate: function(val) {
        //     return "開始時刻：" + val;
        // },
        // filterEndDate: function(val) {
        //     return "終了時刻：" + val;
        // },
        filterTitle: function(val) {
            return "タイトル：" + val;
        },
        filterCycleDate: function(val) {
            return "日付：" + val;
        },
        filterElapsedTime: function(val) {
            var n = val / 1000;
            var hour = (n / (60 * 60)).toFixed(0);
            var min = ((n / 60) % 60).toFixed(0);
            var sec = (n % 60).toFixed(0);
            return "時間：" + hour + ":" + ("0" + min).slice(-2) + ":" + ("0" + sec).slice(-2);
        },
        filterDistance: function(val) {
            return "距離：" + val.toFixed(1) + " km";
        }
    },
    mounted() {
        this.cycleLog = this.getCycleLog();
    },
    methods: {
        onClickTrash(item) {
            this.deleteCycleLog(item.id);
            this.cycleLog = this.getCycleLog();
        }
    }
};
</script>
